// Shared navigation behavior for PWI site header:
// - Desktop mega menu hover/focus open + keyboard navigation
// - Mobile nav drawer toggle + focus trap + nested details accordion animation
//
// Intentionally framework-free and safe to include on every page.

(function () {
  if (window.__PWI_SITE_NAV_INIT) return;
  window.__PWI_SITE_NAV_INIT = true;

  const isReducedMotion =
    window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  const DESKTOP_MQ = window.matchMedia ? window.matchMedia("(min-width: 768px)") : null;
  const isDesktop = () => (DESKTOP_MQ ? DESKTOP_MQ.matches : window.innerWidth >= 768);
  const isMobileMenuViewport = () => (DESKTOP_MQ ? !DESKTOP_MQ.matches : window.innerWidth < 768);

  function moveHeaderToTopOfBody() {
    const header = document.querySelector(".site-header");
    if (!header || !document.body) return;

    const skip = document.querySelector(".skip-to-content");
    const frag = document.createDocumentFragment();

    if (skip) frag.appendChild(skip);
    frag.appendChild(header);

    document.body.prepend(frag);
  }

  function initDesktopMegaMenu() {
    const header = document.querySelector(".site-header");
    const dropdowns = header ? Array.from(header.querySelectorAll("[data-dd]")) : [];
    if (!header || !dropdowns.length) return;

    header.querySelectorAll("[data-dd].is-open").forEach((el) => el.classList.remove("is-open"));

    let active = null;
    const triggerMap = new WeakMap();
    const OPEN_DELAY = 90;
    const CLOSE_DELAY = 180;
    const FOCUS_CLOSE_DELAY = 120;

    const setTriggerExpanded = (dd, expanded) => {
      const trigger = triggerMap.get(dd);
      if (trigger) trigger.setAttribute("aria-expanded", expanded ? "true" : "false");
    };

    const closeNow = (dd, returnFocus = false) => {
      if (!dd) return;
      dd.classList.remove("is-open");
      setTriggerExpanded(dd, false);
      if (returnFocus) {
        const trigger = triggerMap.get(dd);
        if (trigger) trigger.focus();
      }
      if (active === dd) active = null;
    };

    const openNow = (dd) => {
      if (!dd) return;
      if (active && active !== dd) closeNow(active);
      dd.classList.add("is-open");
      setTriggerExpanded(dd, true);
      active = dd;
    };

    const focusFirstLink = (dd) => {
      const panel = dd.querySelector(":scope > .dd-panel");
      if (!panel) return;
      const links = Array.from(panel.querySelectorAll("a[href]"));
      if (links.length) links[0].focus();
    };

    dropdowns.forEach((dd, index) => {
      const trigger = dd.querySelector(":scope > a");
      const panel = dd.querySelector(":scope > .dd-panel");
      if (!trigger || !panel) return;

      const panelId = panel.id || `dd-panel-${index + 1}`;
      panel.id = panelId;
      trigger.setAttribute("aria-haspopup", "true");
      trigger.setAttribute("aria-expanded", "false");
      trigger.setAttribute("aria-controls", panelId);
      triggerMap.set(dd, trigger);

      let openTimer = null;
      let closeTimer = null;
      const clearTimers = () => {
        if (openTimer) clearTimeout(openTimer);
        if (closeTimer) clearTimeout(closeTimer);
        openTimer = null;
        closeTimer = null;
      };

      dd.addEventListener("mouseenter", () => {
        if (!isDesktop()) return;
        if (closeTimer) clearTimeout(closeTimer);
        if (dd.classList.contains("is-open")) return;
        if (openTimer) clearTimeout(openTimer);
        openTimer = setTimeout(() => {
          openNow(dd);
          openTimer = null;
        }, OPEN_DELAY);
      });

      dd.addEventListener("mouseleave", () => {
        if (!isDesktop()) return;
        if (openTimer) clearTimeout(openTimer);
        if (closeTimer) clearTimeout(closeTimer);
        closeTimer = setTimeout(() => {
          closeNow(dd);
          closeTimer = null;
        }, CLOSE_DELAY);
      });

      dd.addEventListener("focusin", () => {
        clearTimers();
        openNow(dd);
      });

      dd.addEventListener("focusout", (e) => {
        if (!dd.contains(e.relatedTarget)) {
          if (openTimer) clearTimeout(openTimer);
          if (closeTimer) clearTimeout(closeTimer);
          closeTimer = setTimeout(() => {
            closeNow(dd);
            closeTimer = null;
          }, FOCUS_CLOSE_DELAY);
        }
      });

      trigger.addEventListener("click", (e) => {
        if (!isDesktop()) return;
        clearTimers();

        // First click opens the mega menu; a second click on the open trigger follows the link.
        if (!dd.classList.contains("is-open")) {
          e.preventDefault();
          openNow(dd);
          return;
        }
      });

      trigger.addEventListener("keydown", (e) => {
        if (!isDesktop()) return;
        clearTimers();

        if (e.key === " " || e.key === "ArrowDown") {
          e.preventDefault();
          openNow(dd);
          focusFirstLink(dd);
          return;
        }

        if (e.key === "Escape") {
          e.preventDefault();
          closeNow(dd, true);
        }
      });
    });

    document.addEventListener("click", (e) => {
      if (!e.target.closest("[data-dd]")) closeNow(active);
    });

    document.addEventListener("keydown", (e) => {
      if (!active || !isDesktop()) return;

      if (e.key === "Escape") {
        e.preventDefault();
        closeNow(active, true);
        return;
      }

      if (e.key === "ArrowDown" || e.key === "ArrowUp") {
        e.preventDefault();
        const panel = active.querySelector(":scope > .dd-panel");
        if (!panel) return;
        const links = Array.from(panel.querySelectorAll("a[href]"));
        if (!links.length) return;
        const idx = links.indexOf(document.activeElement);
        const nextIdx =
          e.key === "ArrowDown"
            ? idx < links.length - 1
              ? idx + 1
              : 0
            : idx > 0
              ? idx - 1
              : links.length - 1;
        links[nextIdx].focus();
      }
    });

    window.addEventListener("resize", () => {
      if (!isDesktop()) closeNow(active);
    });
    window.addEventListener(
      "scroll",
      () => {
        if (!active) return;
        closeNow(active);
      },
      { passive: true }
    );
    document.addEventListener("visibilitychange", () => {
      if (document.hidden) closeNow(active);
    });
  }

  function initMobileMenu() {
    const menuToggle = document.getElementById("mobile-menu-toggle");
    const menuButton = document.getElementById("mobile-menu-button");
    const overlayButton = document.getElementById("mobile-menu-overlay");
    const mobileNav = document.getElementById("mobile-nav");
    const mainContent = document.getElementById("main-content");
    if (!menuToggle || !menuButton || !overlayButton || !mobileNav) return;

    menuToggle.checked = false;
    mobileNav.querySelectorAll("details[open]").forEach((d) => d.removeAttribute("open"));

    const focusableSelector =
      'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), details summary, [tabindex]:not([tabindex="-1"])';

    const getFocusable = () =>
      Array.from(mobileNav.querySelectorAll(focusableSelector)).filter(
        (el) =>
          el.getAttribute("aria-hidden") !== "true" &&
          (el.offsetParent !== null || el === document.activeElement)
      );

    const trapFocus = (e) => {
      if (!menuToggle.checked || e.key !== "Tab") return;
      const focusables = getFocusable();
      if (!focusables.length) return;
      const first = focusables[0];
      const last = focusables[focusables.length - 1];
      if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus();
      } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus();
      }
    };

    const syncMenuState = () => {
      const menuIsOpen = menuToggle.checked && isMobileMenuViewport();
      menuButton.setAttribute("aria-expanded", menuIsOpen ? "true" : "false");
      menuButton.classList.toggle("is-active", menuIsOpen);
      document.documentElement.style.overflowY = menuIsOpen ? "hidden" : "";
      document.documentElement.style.paddingRight = "";

      if (mainContent) {
        if (menuIsOpen) mainContent.setAttribute("inert", "");
        else mainContent.removeAttribute("inert");
      }

      if (menuIsOpen) {
        document.addEventListener("keydown", trapFocus);
        requestAnimationFrame(() => {
          const first = getFocusable()[0];
          if (first) first.focus();
        });
      } else {
        document.removeEventListener("keydown", trapFocus);
      }
    };

    syncMenuState();

    const allDetails = Array.from(mobileNav.querySelectorAll("details"));
    allDetails.forEach((details) => {
      const summary = details.querySelector("summary");
      if (!summary || details.__panel) return;
      const panel = document.createElement("div");
      panel.className = "accordion-panel";
      panel.style.transition = isReducedMotion ? "none" : "height 260ms ease";
      while (summary.nextSibling) panel.appendChild(summary.nextSibling);
      details.appendChild(panel);
      details.__panel = panel;
      panel.style.height = details.hasAttribute("open") ? "auto" : "0px";
      summary.addEventListener("click", (e) => {
        e.preventDefault();
        toggle(details);
      });
    });

    function getPanel(details) {
      return details.__panel || details.querySelector(".accordion-panel");
    }

    function open(details) {
      const panel = getPanel(details);
      if (!panel) return;
      details.setAttribute("open", "");
      if (isReducedMotion) {
        panel.style.height = "auto";
        return;
      }
      panel.style.height = "0px";
      const target = panel.scrollHeight;
      requestAnimationFrame(() => {
        panel.style.height = target + "px";
      });
      const onEnd = (ev) => {
        if (ev.propertyName !== "height") return;
        panel.removeEventListener("transitionend", onEnd);
        if (details.hasAttribute("open")) panel.style.height = "auto";
      };
      panel.addEventListener("transitionend", onEnd);
    }

    function close(details) {
      const panel = getPanel(details);
      if (!panel) {
        details.removeAttribute("open");
        return;
      }
      if (isReducedMotion) {
        details.removeAttribute("open");
        panel.style.height = "0px";
        return;
      }
      const current = panel.getBoundingClientRect().height;
      panel.style.height = current + "px";
      panel.offsetHeight;
      requestAnimationFrame(() => {
        panel.style.height = "0px";
      });
      const onEnd = (ev) => {
        if (ev.propertyName !== "height") return;
        panel.removeEventListener("transitionend", onEnd);
        details.removeAttribute("open");
      };
      panel.addEventListener("transitionend", onEnd);
    }

    function closeSiblings(details) {
      const parent = details.parentElement;
      if (!parent) return;
      Array.from(parent.children).forEach((el) => {
        if (
          el !== details &&
          el.tagName &&
          el.tagName.toLowerCase() === "details" &&
          el.hasAttribute("open")
        ) {
          close(el);
        }
      });
    }

    function toggle(details) {
      if (details.hasAttribute("open")) return close(details);
      closeSiblings(details);
      open(details);
    }

    function closeAll() {
      mobileNav.querySelectorAll("details[open]").forEach((d) => close(d));
    }

    menuToggle.addEventListener("change", () => {
      syncMenuState();
      if (!menuToggle.checked) closeAll();
    });

    window.addEventListener("resize", () => {
      if (!isMobileMenuViewport()) {
        menuToggle.checked = false;
        closeAll();
      }
      syncMenuState();
    });

    menuButton.addEventListener("click", () => {
      menuToggle.checked = !menuToggle.checked;
      menuToggle.dispatchEvent(new Event("change"));
    });

    overlayButton.addEventListener("click", () => {
      if (!menuToggle.checked) return;
      menuToggle.checked = false;
      menuToggle.dispatchEvent(new Event("change"));
    });

    document.addEventListener("keydown", (e) => {
      if (e.key !== "Escape" || !menuToggle.checked) return;
      menuToggle.checked = false;
      menuToggle.dispatchEvent(new Event("change"));
      menuButton.focus();
    });

    mobileNav.addEventListener("click", (e) => {
      const a = e.target.closest("a");
      if (!a) return;
      menuToggle.checked = false;
      menuToggle.dispatchEvent(new Event("change"));
    });
  }

  function initAriaCurrent() {
    const getBasename = (href) => {
      if (!href) return "";
      const raw = String(href).trim();
      if (!raw || raw.startsWith("#") || raw.startsWith("mailto:") || raw.startsWith("tel:")) {
        return "";
      }
      try {
        const url = new URL(raw, window.location.href);
        const base = url.pathname.split("/").pop();
        return base || "index.html";
      } catch {
        const clean = raw.split("#")[0].split("?")[0];
        const base = clean.split("/").pop();
        return base || "";
      }
    };

    const currentBase = (() => {
      try {
        const url = new URL(window.location.href);
        const base = url.pathname.split("/").pop();
        return base || "index.html";
      } catch {
        const base = window.location.pathname.split("/").pop();
        return base || "index.html";
      }
    })();

    document
      .querySelectorAll('.site-header a[href], a.rowlink[href]')
      .forEach((a) => {
        a.removeAttribute("aria-current");
        a.classList.remove("is-active");
        a.closest?.(".rowlike")?.classList.remove("is-active");
      });

    document.querySelectorAll(".site-header a[href], a.rowlink[href]").forEach((a) => {
      const base = getBasename(a.getAttribute("href"));
      if (!base) return;
      if (base === currentBase || (currentBase === "" && base === "index.html")) {
        a.setAttribute("aria-current", "page");
        a.classList.add("is-active");
        a.closest?.(".rowlike")?.classList.add("is-active");
      }
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    // Allows placing the NAV markup at the bottom of the HTML source while keeping
    // correct DOM order (accessibility + tab order) by moving it to the top.
    moveHeaderToTopOfBody();
    initDesktopMegaMenu();
    initMobileMenu();
    initAriaCurrent();
  });
})();
